 19→import java.util.Arrays;
 20→import java.util.List;
 21→import java.util.Map;
 22→
 23→/**
 24→ * 认证接口：OAuth2 登录、回调、获取当前用户
 25→ */
 26→@Slf4j
 27→@RestController
 28→@RequestMapping("/api/auth")
 29→public class AuthController {
 30→
 31→    private final AuthService authService;
 32→    private final Environment environment;
 33→
 34→    @Value("${spring.security.oauth2.client.registration.default.client-id}")
 35→    private String clientId;
 36→
 37→    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
 38→    private String authorizationUri;
 39→
 40→    @Value("${spring.security.oauth2.client.registration.default.scope:openid,profile,email}")
 41→    private String scope;
 42→
 43→    @Value("${app.frontend-url:http://localhost:5173}")
 44→    private String frontendUrl;
 45→
 46→    public AuthController(AuthService authService, Environment environment) {
 47→        this.authService = authService;
 48→        this.environment = environment;
 49→    }
 50→
 51→    private boolean isDevProfile() {
 52→        return Arrays.asList(environment.getActiveProfiles()).contains("dev");
 53→    }
 54→
 55→    /**
 56→     * 构建 OA 授权地址并 302 重定向；dev 环境直接签发 JWT 跳回前端
 57→     */
 58→    @GetMapping("/oauth2/login")
 59→    public ResponseEntity<Void> login(HttpServletRequest request) {
 60→        if (isDevProfile()) {
 61→            String token = authService.devLogin();
 62→            String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
 63→            log.info("[lbl][Auth][LOGIN] Dev 模式: 跳过 OAuth2, 直接重定向到前端");
 64→            return ResponseEntity.status(HttpStatus.FOUND)
 65→                    .header(HttpHeaders.LOCATION, callbackUrl)
 66→                    .build();
 67→        }
 68→
 69→        String redirectUri = buildRedirectUri(request);
 70→
 71→        var builder = UriComponentsBuilder.fromHttpUrl(authorizationUri)
 72→                .queryParam("client_id", clientId)
 73→                .queryParam("redirect_uri", redirectUri)
 74→                .queryParam("response_type", "code");
 75→        if (scope != null && !scope.isBlank()) {
 76→            builder.queryParam("scope", scope);
 77→        }
 78→        String authorizeUrl = builder.toUriString();
 79→
 80→        log.debug("[lbl][Auth][LOGIN] OAuth2 登录重定向: {}", authorizeUrl);
 81→
 82→        return ResponseEntity.status(HttpStatus.FOUND)
 83→                .header(HttpHeaders.LOCATION, authorizeUrl)
 84→                .build();
 85→    }
 86→
 87→    /**
 88→     * OAuth2 回调：用 code 换 token，302 重定向到前端并携带 token
 89→     */
 90→    @GetMapping("/oauth2/callback")
 91→    public ResponseEntity<Void> callback(@RequestParam("code") String code,
 92→                                         HttpServletRequest request) {
 93→        String redirectUri = buildRedirectUri(request);
 94→        String token = authService.handleOAuthCallback(code, redirectUri);
 95→        log.info("[lbl][Auth][CALLBACK] OAuth2 回调完成, 已签发 token, 重定向到前端");
 96→
 97→        String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
 98→        return ResponseEntity.status(HttpStatus.FOUND)
 99→                .header(HttpHeaders.LOCATION, callbackUrl)
100→                .build();
101→    }
102→
103→    /**
104→     * 获取当前登录用户信息
105→     */
106→    @GetMapping("/me")
107→    public Result<UserInfo> me() {
108→        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
109→        Long userId = Long.parseLong(auth.getName());
110→        UserInfo userInfo = authService.getCurrentUser(userId);
111→        return Result.ok(userInfo);
112→    }
113→
114→    /**
115→     * Dev 环境本地登录：自定义用户名和角色（仅 dev profile 可用）
116→     * 请求体: { "username": "test_user", "isAdmin": true }
117→     */
118→    @PostMapping("/oauth2/dev-login")
119→    public Result<Map<String, String>> devLoginCustom(@RequestBody Map<String, Object> body) {
120→        if (!isDevProfile()) {
121→            return Result.fail(403, "仅 dev 环境可用");
122→        }
123→        String username = (String) body.get("username");
124→        if (username == null || username.isBlank()) {
125→            return Result.fail(400, "用户名不能为空");
126→        }
127→        Boolean isAdmin = body.get("isAdmin") != null && (Boolean) body.get("isAdmin");
128→        String token = authService.devLoginWithCustom(username.trim(), isAdmin);
129→        log.info("[lbl][Auth][LOGIN] Dev 自定义登录, username={}, isAdmin={}", username, isAdmin);
130→        return Result.ok(Map.of("token", token));
131→    }
132→
133→    /**
134→     * Dev 环境批量注册 mock 用户（仅 dev profile 可用）
135→     * 请求体: { "users": [{ "userId": 10001, "username": "mock_1", "displayName": "模拟用户1" }, ...] }
136→     */
137→    @PostMapping("/dev/register")
138→    public Result<Integer> devRegister(@RequestBody Map<String, List<Map<String, Object>>> body) {
139→        if (!isDevProfile()) {
140→            return Result.fail(403, "仅 dev 环境可用");
141→        }
142→        List<Map<String, Object>> users = body.get("users");
143→        if (users == null || users.isEmpty()) {
144→            return Result.fail(400, "users 不能为空");
145→        }
146→        int count = 0;
147→        for (Map<String, Object> u : users) {
148→            Long userId = ((Number) u.get("userId")).longValue();
149→            String username = (String) u.get("username");
150→            String displayName = (String) u.get("displayName");
151→            authService.registerMockUser(userId, username, displayName);
152→            count++;
153→        }
154→        return Result.ok(count);
155→    }
156→
157→    /**
158→     * 根据当前请求构建 OAuth2 回调地址
