 24→/**
 25→ * 认证服务：处理 OAuth2 回调、用户查询
 26→ */
 27→@Slf4j
 28→@Service
 29→public class AuthService {
 30→
 31→    private final SysUserMapper sysUserMapper;
 32→    private final JwtUtil jwtUtil;
 33→    private final RestTemplate restTemplate;
 34→
 35→    @Value("${spring.security.oauth2.client.registration.default.client-id}")
 36→    private String clientId;
 37→
 38→    @Value("${spring.security.oauth2.client.registration.default.client-secret}")
 39→    private String clientSecret;
