 52→
 53→    @Value("${collabspace.internal-token}")
 54→    private String collabspaceInternalToken;
 55→
 56→    public AuthService(SysUserMapper sysUserMapper, JwtUtil jwtUtil) {
 57→        this.sysUserMapper = sysUserMapper;
 58→        this.jwtUtil = jwtUtil;
 59→        this.restTemplate = new RestTemplate();
 60→    }
 61→
 62→    /**
 63→     * 处理 OAuth2 回调：用 code 换 token，获取用户信息，同步到本地用户表，生成 JWT
 64→     *
 65→     * @param code         授权码
 66→     * @param redirectUri  回调地址（需与请求授权时一致）
 67→     * @return JWT token 字符串
 68→     */
 69→    public String handleOAuthCallback(String code, String redirectUri) {
 70→        // 1. 用 code 换 access_token（OA 的 token 响应中直接包含用户信息）
 71→        Map<String, Object> tokenResponse = exchangeToken(code, redirectUri);
 72→        log.info("[lbl][Auth][OAUTH] token 响应: {}", tokenResponse);
 73→
 74→        // 2. 从 token 响应中提取用户信息（OA 返回 user_info 嵌套对象）
 75→        @SuppressWarnings("unchecked")
 76→        Map<String, Object> oaUserInfo = (Map<String, Object>) tokenResponse.get("user_info");
 77→        if (oaUserInfo == null) {
 78→            log.error("[lbl][Auth][OAUTH] token 响应中没有 user_info 字段, keys={}", tokenResponse.keySet());
 79→            throw new BizException(ErrorCode.INTERNAL_ERROR);
 80→        }
 81→        log.info("[lbl][Auth][OAUTH] OA 用户信息: {}", oaUserInfo);
 82→        String email = (String) oaUserInfo.get("email");
 83→        String displayName = (String) oaUserInfo.get("nickname");
 84→
 85→        // 3. 调用 CollabSpace 内部接口，检查用户是否为成员
 86→        checkUserInCollabSpace(email, displayName);
 87→
 88→        // 4. 按 email（username）查库，有则更新，无则创建
 89→        SysUser user = sysUserMapper.selectOne(
 90→                new LambdaQueryWrapper<SysUser>().eq(SysUser::getUsername, email));
 91→
 92→        // 硬编码管理员：扶苏
 93→        boolean isAdmin = "扶苏".equals(displayName);
 94→
 95→        if (user != null) {
 96→            user.setOaUserId(email);
 97→            user.setDisplayName(displayName);
 98→            user.setIsAdmin(isAdmin);
 99→            user.setUpdatedAt(LocalDateTime.now());
100→            sysUserMapper.updateById(user);
101→            log.info("[lbl][Auth][LOGIN] 用户登录(已存在), userId={}, email={}, isAdmin={}", user.getId(), email, isAdmin);
102→        } else {
103→            user = SysUser.builder()
104→                    .oaUserId(email)
105→                    .username(email)
106→                    .displayName(displayName)
107→                    .isAdmin(isAdmin)
108→                    .createdAt(LocalDateTime.now())
109→                    .updatedAt(LocalDateTime.now())
110→                    .build();
111→            sysUserMapper.insert(user);
112→            log.info("[lbl][Auth][LOGIN] 用户首次登录(新建), userId={}, email={}, isAdmin={}", user.getId(), email, isAdmin);
113→        }
114→
115→        // 5. 生成 JWT
116→        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
117→    }
118→
119→    /**
120→     * 开发环境登录：直接创建/获取 mock 用户并签发 JWT，跳过 OAuth2 流程
121→     */
122→    public String devLogin() {
123→        String devOaUserId = "dev-mock-001";
124→        SysUser user = sysUserMapper.selectOne(
125→                new LambdaQueryWrapper<SysUser>().eq(SysUser::getOaUserId, devOaUserId));
126→
127→        if (user == null) {
128→            user = SysUser.builder()
129→                    .oaUserId(devOaUserId)
130→                    .username("dev_user")
131→                    .displayName("开发测试用户")
132→                    .isAdmin(true)
133→                    .createdAt(LocalDateTime.now())
134→                    .updatedAt(LocalDateTime.now())
135→                    .build();
136→            sysUserMapper.insert(user);
137→            log.info("[lbl][Auth][LOGIN] Dev 模式: 创建 mock 用户, userId={}", user.getId());
138→        } else {
139→            log.info("[lbl][Auth][LOGIN] Dev 模式: 使用已有 mock 用户, userId={}", user.getId());
140→        }
141→
142→        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
143→    }
144→
145→    /**
146→     * 注册 mock 用户（仅 dev 环境使用）：按指定 userId 创建用户，已存在则跳过
147→     *
148→     * @param userId      指定的用户 ID
149→     * @param username    用户名
150→     * @param displayName 显示名称
151→     * @return 用户信息
152→     */
153→    public SysUser registerMockUser(Long userId, String username, String displayName) {
154→        SysUser existing = sysUserMapper.selectById(userId);
155→        if (existing != null) {
