191→                    user.getId(), username, isAdmin);
192→        } else {
193→            // 更新角色（每次登录可能选不同角色）
194→            user.setIsAdmin(isAdmin);
195→            user.setUpdatedAt(LocalDateTime.now());
196→            sysUserMapper.updateById(user);
197→            log.info("[lbl][Auth][LOGIN] Dev 自定义登录: 使用已有用户, userId={}, username={}, isAdmin={}",
198→                    user.getId(), username, isAdmin);
199→        }
200→
201→        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
202→    }
203→
204→    /**
205→     * 获取当前用户信息
206→     *
207→     * @param userId 用户 ID
208→     * @return 用户信息 DTO
209→     */
210→    public UserInfo getCurrentUser(Long userId) {
211→        SysUser user = sysUserMapper.selectById(userId);
212→        if (user == null) {
213→            throw new BizException(ErrorCode.NOT_FOUND);
214→        }
215→
216→        UserInfo info = new UserInfo();
