221→        info.setIsAdmin(user.getIsAdmin());
222→        return info;
223→    }
224→
225→    /**
226→     * 调用 CollabSpace 内部接口检查用户是否存在，不存在则抛出业务异常
227→     *
228→     * @param email    用户邮箱
229→     * @param nickName 用户花名
230→     */
231→    private void checkUserInCollabSpace(String email, String nickName) {
232→        String url = collabspaceBaseUrl + "/api/v1/internal/user/checkExist";
233→        log.info("[lbl][Auth][CHECK] 调用 CollabSpace 检查用户, email={}, nickName={}", email, nickName);
234→
235→        HttpHeaders headers = new HttpHeaders();
236→        headers.setContentType(MediaType.APPLICATION_JSON);
237→        headers.set("X-Internal-Token", collabspaceInternalToken);
238→
239→        // 优先用邮箱查询
240→        Map<String, String> body = new java.util.HashMap<>();
241→        if (email != null && !email.isBlank()) {
242→            body.put("email", email);
243→        }
244→        if (nickName != null && !nickName.isBlank()) {
245→            body.put("nickName", nickName);
246→        }
247→
248→        try {
249→            HttpEntity<Map<String, String>> request = new HttpEntity<>(body, headers);
250→            ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
251→                    url, HttpMethod.POST, request, new ParameterizedTypeReference<>() {});
252→
253→            Map<String, Object> responseBody = response.getBody();
254→            if (responseBody == null) {
255→                log.error("[lbl][Auth][CHECK] CollabSpace 响应为空, email={}", email);
256→                throw new BizException(ErrorCode.INTERNAL_ERROR);
257→            }
258→
259→            Boolean success = (Boolean) responseBody.get("success");
260→            if (!Boolean.TRUE.equals(success)) {
261→                log.error("[lbl][Auth][CHECK] CollabSpace 接口调用失败, response={}", responseBody);
262→                throw new BizException(ErrorCode.INTERNAL_ERROR);
263→            }
264→
265→            @SuppressWarnings("unchecked")
266→            Map<String, Object> data = (Map<String, Object>) responseBody.get("data");
267→            Boolean exist = data != null ? (Boolean) data.get("exist") : false;
268→
269→            if (!Boolean.TRUE.equals(exist)) {
270→                log.warn("[lbl][Auth][CHECK] 用户不是 CollabSpace 成员, email={}, nickName={}", email, nickName);
271→                throw new BizException(ErrorCode.USER_NOT_IN_COLLABSPACE);
