    /**
     * 获取当前用户信息
     *
     * @param userId 用户 ID
     * @return 用户信息 DTO
     */
    public UserInfo getCurrentUser(Long userId) {
        SysUser user = sysUserMapper.selectById(userId);
        if (user == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }

        UserInfo info = new UserInfo();
        info.setId(user.getId());
        info.setOaUserId(user.getOaUserId());
        info.setUsername(user.getUsername());
        info.setDisplayName(user.getDisplayName());
        info.setIsAdmin(user.getIsAdmin());
        return info;
    }

    /**
     * 调用 CollabSpace 内部接口检查用户是否存在，不存在则抛出业务异常
     *
     * @param email    用户邮箱
     * @param nickName 用户花名
     */
    private void checkUserInCollabSpace(String email, String nickName) {
        log.info("[lbl][Auth][CHECK] 调用 CollabSpace 检查用户, email={}, nickName={}", email, nickName);

        // 先查邮箱，再查花名，两个都明确存在才放行
        Boolean emailExist = callCheckExist("email", email);
        Boolean nickNameExist = callCheckExist("nickName", nickName);

        // 任一接口异常(返回null)则跳过校验，不阻断登录
        if (emailExist == null || nickNameExist == null) {
            log.warn("[lbl][Auth][CHECK] CollabSpace 接口异常或未上线, 跳过校验, email={}, nickName={}", email, nickName);
            return;
        }

        if (!emailExist || !nickNameExist) {
            log.warn("[lbl][Auth][CHECK] 用户不是 CollabSpace 成员, emailExist={}, nickNameExist={}, email={}, nickName={}",
                    emailExist, nickNameExist, email, nickName);
            throw new BizException(ErrorCode.USER_NOT_IN_COLLABSPACE);
        }

        log.info("[lbl][Auth][CHECK] 用户验证通过(邮箱+花名均存在), email={}, nickName={}", email, nickName);
    }

    /**
     * 单次调用 CollabSpace checkExist 接口
     *
     * @param field 查询字段名（email 或 nickName）
     * @param value 查询值
     * @return true=存在, false=不存在, null=接口异常(未上线/网络错误等)
     */
    private Boolean callCheckExist(String field, String value) {
        if (value == null || value.isBlank()) {
            log.warn("[lbl][Auth][CHECK] {}为空, 跳过该项检查", field);
            return null;
        }

        String url = collabspaceBaseUrl + "/api/v1/internal/user/checkExist";
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        headers.set("X-Internal-Token", collabspaceInternalToken);

        Map<String, String> body = Map.of(field, value);

        try {
            HttpEntity<Map<String, String>> request = new HttpEntity<>(body, headers);
            ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
                    url, HttpMethod.POST, request, new ParameterizedTypeReference<>() {});

            Map<String, Object> responseBody = response.getBody();
            if (responseBody == null) {
                log.warn("[lbl][Auth][CHECK] CollabSpace 响应为空(接口可能未上线), field={}, value={}", field, value);
                return null;
            }

            Boolean success = (Boolean) responseBody.get("success");
            if (!Boolean.TRUE.equals(success)) {
                log.warn("[lbl][Auth][CHECK] CollabSpace 接口返回失败(接口可能未上线), field={}, response={}", field, responseBody);
                return null;
            }

            @SuppressWarnings("unchecked")
            Map<String, Object> data = (Map<String, Object>) responseBody.get("data");
            Boolean exist = data != null ? (Boolean) data.get("exist") : null;
            log.info("[lbl][Auth][CHECK] CollabSpace 查询结果, field={}, value={}, exist={}", field, value, exist);
            return Boolean.TRUE.equals(exist);
        } catch (Exception e) {
            log.warn("[lbl][Auth][CHECK] 调用 CollabSpace 异常(接口可能未上线), field={}, value={}, error={}", field, value, e.getMessage());
            return null;
        }
    }

    /**
     * 用授权码换取 token（OA 的响应中包含 access_token 和 user_info）
     */
    private Map<String, Object> exchangeToken(String code, String redirectUri) {
        log.info("[lbl][Auth][OAUTH] 换取 token, tokenUri={}, redirectUri={}", tokenUri, redirectUri);
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));

        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
        params.add("grant_type", "authorization_code");
        params.add("client_id", clientId);
        params.add("client_secret", clientSecret);
        params.add("code", code);
        params.add("redirect_uri", redirectUri);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);

        ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
                tokenUri,
                HttpMethod.POST,
                request,
                new ParameterizedTypeReference<>() {});

        Map<String, Object> body = response.getBody();
        if (body == null || !body.containsKey("access_token")) {
            log.error("[lbl][Auth][OAUTH] 换取 token 失败, responseBody={}", body);
            throw new BizException(ErrorCode.INTERNAL_ERROR);
        }
        return body;
    }

    /**
     * 用 access_token 获取 OA 用户信息
     */
    private Map<String, Object> fetchOaUserInfo(String accessToken) {
        log.info("[lbl][Auth][OAUTH] 获取 OA 用户信息, userInfoUri={}, tokenPrefix={}",
                userInfoUri, accessToken.substring(0, Math.min(20, accessToken.length())));
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));
        HttpEntity<Void> request = new HttpEntity<>(headers);
        log.info("[lbl][Auth][OAUTH] 请求头: {}", headers);

        try {
            ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
                    userInfoUri,
                    HttpMethod.GET,
                    request,
                    new ParameterizedTypeReference<>() {});

            Map<String, Object> body = response.getBody();
            log.info("[lbl][Auth][OAUTH] OA 用户信息响应: {}", body);
            if (body == null) {
                log.error("[lbl][Auth][OAUTH] 获取用户信息失败, responseBody 为空");
                throw new BizException(ErrorCode.INTERNAL_ERROR);
            }
            return body;
        } catch (HttpClientErrorException e) {
            log.error("[lbl][Auth][OAUTH] 调用 OA 用户信息失败, status={}, body={}, headers={}",
                    e.getStatusCode(), e.getResponseBodyAsString(), e.getResponseHeaders());
            throw e;
        }
    }
}

